import{_ as a,o as i,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"31. Qualification Allowance","description":"","frontmatter":{"title":"31. Qualification Allowance","eba":"Nurses and Midwives 2024-2028","topics":["allowances","preliminary","staffing"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/31-qualification-allowance.md","filePath":"ebas/nurses-midwives/allowances/31-qualification-allowance.md"}'),o={name:"ebas/nurses-midwives/allowances/31-qualification-allowance.md"};function r(s,e,l,c,p,d){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_31-qualification-allowance" tabindex="-1">31. Qualification Allowance <a class="header-anchor" href="#_31-qualification-allowance" aria-label="Permalink to &quot;31. Qualification Allowance&quot;">​</a></h1><p>Note: See <a href="/eba/ebas/allied-health/preliminary/4-definitions.html">clause 4.2</a> (Definitions) regarding the interpretation of relevance.</p><p><strong>31.1</strong> Entitlement</p><p><strong>(a)</strong> An Employee will be entitled to a qualification allowance, where an Employee has a:</p><p><strong>(i)</strong> relevant qualification, which includes where at least one component is relevant, as described in <a href="/eba/ebas/allied-health/preliminary/4-definitions.html">clause 4.2</a>, in addition to their base nursing or midwifery qualification;</p><p><strong>(ii)</strong> base qualification that is a double degree or Masters degree; or</p><p><strong>(iii)</strong> a Certificate IV in Training and Assessment.</p><p><strong>(b)</strong> In the case of the entitlement under subclause 31.1(a)(ii), the qualification allowance will be payable after one year of experience in an area where the qualification is relevant.</p><p><strong>(c)</strong> In the case of the entitlement under subclause 31.1(a)(iii), the qualification allowance will be payable only where the Employee is required by their Employer to hold a Certificate IV in Training and Assessment (or equivalent).</p><p><strong>31.2</strong> One Qualification Allowance Only</p><p>An Employee holding more than one qualification is entitled to one qualification allowance only, being the allowance for the highest qualification held for all ordinary hours worked, including where an Employee has multiple roles.</p><p><strong>31.3</strong> Evidence - Qualifications held on commencement with Employer</p><p><strong>(a)</strong> An Employer must maintain a work system that requests the submission of evidence and records the qualification/s held by the Employee who commences after this Agreement comes into operation.</p><p><strong>(b)</strong> Where an Employee who commences after this Agreement comes into operation holds a relevant qualification as described at clause 31.1, the Employee will be entitled to payment from the commencement of Employment except where the Employee did not advise the Employer of the relevant qualification in accordance with the Employer’s work system including the provision of evidence.</p><p><strong>(c)</strong> The exception at (b) does not apply where:</p><p><strong>(i)</strong> The Employer did not maintain a work system as described at (a), or</p><p><strong>(ii)</strong> The Employer has otherwise recognised the relevant qualification such as by engaging the Employee in a position where the relevant qualification is mandatory.</p><p><strong>31.4</strong> Evidence - Qualifications obtained during Employment with Employer</p><p><strong>(a)</strong> An Employee claiming an entitlement to a qualification allowance must provide to the Employer evidence of that Employee holding the qualification for which the entitlement is claimed.</p><p><strong>(b)</strong> An Employee claiming an entitlement to a qualification allowance will receive a substantive written response from the Employer (confirming its applicability or otherwise) within 28 days of the Employee complying with subclause 31.4(a).</p><p><strong>(c)</strong> An Employee will meet the evidence requirements described in subclause 31.4(a) when they have provided the Employer with evidence from the education/training provider that would satisfy a reasonable person that the Employee has obtained the qualification for which the allowance is claimed, for example:</p><p><strong>(i)</strong> the award of the qualification;</p><p><strong>(ii)</strong> the certificate of the qualification; or</p><p><strong>(iii)</strong> transcript from the education/training provider,</p><p>payable from the FFPPOOA on or after the evidence is provided.</p><p><strong>31.5</strong> Rates for Qualification Allowances</p><p><strong>(a)</strong> Registered Nurses and Midwives</p><p>A Registered Nurse or Midwife entitled to a qualification allowance under this clause will be paid, in addition to the Employee&#39;s salary, as follows:</p><p><strong>(i)</strong> The rate for &quot;RN/Midwife Hospital / Grad Certificate&quot; in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2 – for a Hospital Certificate or Graduate Certificate or equivalent. An equivalent may include a Certificate obtained from training or an education facilities provider (such as infection control certificates from the Mayfield Centre) where the programmes are equivalent to a University Graduate Certificate and the training/education provider verifies that in writing;</p><p><strong>(ii)</strong> The rate for &quot;RN/Midwife Post Grad Diploma or Degree&quot; in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2 – for a Postgraduate Diploma, Degree or a Double Degree;</p><p><strong>(iii)</strong> The rate for &quot;RN/Midwife Masters&quot; in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2 – for a Masters;</p><p><strong>(iv)</strong> The rate for &quot;RN/Midwife PhD&quot; in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2 – for a Doctorate or a PhD.</p><p><strong>(b)</strong> Enrolled Nurses</p><p><strong>(i)</strong> An Enrolled Nurse who holds a relevant certificate or qualification will be paid the following allowance:</p><p><strong>(A)</strong> The rate for &quot;EN 6 MONTH COURSE&quot; in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2 – for a certificate or qualification for a course of six months&#39; duration.</p><p><strong>(B)</strong> The rate for &quot;EN 12 MONTH COURSE&quot; in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2 – for a certificate or qualification for a course of 12 months&#39; duration.</p><p><strong>(ii)</strong> Where the course is offered in both full time and less than full time modes, the references in this clause to 6 months and 12 months are a reference to the course duration in full time mode.</p><p><strong>(c)</strong> Enrolled Nurses Post Basic Courses</p><p>Post Basic Nursing Courses in Australia for Enrolled Nurses in Victoria are as follows:</p><p>Communicable Diseases Nursing (12 Fairfield Hospital months)</p><p>Maternity Nursing (six months) The Royal Women&#39;s Hospital</p><p>Operating Theatre Nursing (six months) The Royal Women&#39;s Hospital</p><p>Geriatric Nursing (six months) Mount Royal Hospital Poplar Road Parkville, 3052</p><p>Notwithstanding anything contained elsewhere in this clause an Enrolled Nurse who holds any other relevant certificate or qualification which may from time to time be approved by the NMBA is entitled to a qualification allowance in accordance with this clause.</p><p><strong>(d)</strong> Exclusion – Enrolled Nurses</p><p>An Enrolled Nurse is not entitled to a qualification allowance for a pre- registration or post-registration course leading to an endorsement to administer medication.</p><p><strong>(e)</strong> Certificate IV in Training and Assessment Allowance rate</p><p>The rate for &quot;Cert IV TAE Allowance&quot; as set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2.</p><p><strong>31.6</strong> Relocation</p><p>An Employee in receipt of a qualification allowance who is relocated by the Employer in accordance with <a href="/eba/ebas/nurses-midwives/allowances/37-travelling-and-relocation.html">clause 37</a> (Travelling and Relocation) or <a href="/eba/ebas/nurses-midwives/allowances/41A-change-of-ward-allowance.html">clause 41A</a> (Change of Ward Allowance) of this Agreement into an area where the qualification is not relevant, will continue to receive the qualification allowance.</p><p><strong>31.7</strong> Payment During Leave</p><p><strong>(a)</strong> A qualification allowance will be paid during all periods of leave except, in respect to a Registered Nurse or Midwife, sick leave beyond 21 days in any 12- month period and long service leave.</p><p><strong>(b)</strong> In the case of annual leave, a qualification allowance is added to those components detailed at <a href="/eba/ebas/nurses-midwives/leave/57-annual-leave.html">clause 57.8</a> (Annual leave loading or penalties) that form the &#39;projected roster&#39; leave loading mode. If the Employee receives the 17.5% leave loading mode, the Employee does not receive the allowance in addition to leave loading.</p><p><strong>31.8</strong> Pro rata entitlement</p><p>The allowance is to be paid on a pro rata basis for part-time and casual Employees.</p>',55)])])}const f=a(o,[["render",r]]);export{u as __pageData,f as default};
